1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	  cursed?: boolean;
9	};
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_SIZE = 3;
24	const BLOCK_PREMIUM = 60;
25	
26	export function quote(customer: Customer, items: Item[]): number {
27	  const countsByType: Record<string, number> = {};
28	  for (const item of items) {
29	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
30	  }
31	
32	  let policyBase = 0;
33	  for (const type of Object.keys(countsByType)) {
34	    const count = countsByType[type];
35	    const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
36	    const groupBase = isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
37	    policyBase += groupBase;
38	  }
39	
40	  let itemSurcharges = 0;
41	  for (const item of items) {
42	    const itemBase = BASE_PREMIUMS[item.type];
43	    if (item.cursed) {
44	      itemSurcharges += itemBase / 2;
45	    }
46	  }
47	
48	  const firstInsurance = policyBase / 10;
49	  return Math.ceil(policyBase + itemSurcharges + firstInsurance) + PROCESSING_FEE;
50	}
